  title: 'My API',
  version: '1.0.0',
});

const outputPath = path.join(process.cwd(), 'openapi.json');
fs.writeFileSync(outputPath, JSON.stringify(openApiDocument, null, 2), 'utf-8');

console.log('OpenAPI specification generated at openapi.json');

